import { BrowserRouter as Router, Routes, Route, NavLink, Navigate, useLocation, useNavigate } from 'react-router-dom';
import { LayoutDashboard, UtensilsCrossed, QrCode, LogOut, Users, Settings as SettingsIcon, Menu, X, Banknote } from 'lucide-react';
import { useState } from 'react';
import Dashboard from './pages/Dashboard';
import MenuManager from './pages/MenuManager';
import QRGenerator from './pages/QRGenerator';
import TableDetail from './pages/TableDetail';
import Team from './pages/Team';
import Settings from './pages/Settings';
import Login from './pages/Login';
import Kitchen from './pages/Kitchen';
import Sales from './pages/Sales';
import Suppliers from './pages/Suppliers';


const RequireAuth = ({ children }) => {
  const user = localStorage.getItem('chefia_user');
  if (!user) return <Navigate to="/login" />;
  return children;
};

const LayoutWrapper = ({ children }) => {
  const navigate = useNavigate();
  const location = useLocation();
  let user = {};
  try {
    user = JSON.parse(localStorage.getItem('chefia_user') || '{}');
  } catch (e) {
    console.error('Error parsing user', e);
  }

  const handleLogout = () => {
    localStorage.removeItem('chefia_user');
    navigate('/login');
  };

  const navItems = [
    { label: 'Visão Geral', path: '/', icon: LayoutDashboard },
    { label: 'Vendas (Caixa)', path: '/sales', icon: Banknote },
    { label: 'Cozinha (KDS)', path: '/kitchen', icon: UtensilsCrossed },
    { label: 'Cardápio', path: '/menu', icon: UtensilsCrossed },
    { label: 'Fornecedores', path: '/suppliers', icon: Users },
    { label: 'Equipe', path: '/team', icon: Users },
    { label: 'QR Code', path: '/qr', icon: QrCode },
    { label: 'Configuração', path: '/settings', icon: SettingsIcon },
  ];

  const userRole = user.role || 'gerente';

  const PERMISSIONS = {
    'gerente': '*',
    'recepcao': ['/', '/table'], // Dashboard has the map (Entry/Exit control)
    'cozinha': ['/kitchen'],
    'bar': ['/kitchen']
  };

  const allowedPaths = PERMISSIONS[userRole] || [];

  const filteredNavItems = navItems.filter(item => {
    if (userRole === 'gerente') return true;
    // Special logic: 'recepcao' needs access to '/' (Dashboard) but technically '/table' is dynamic, 
    // so we filter sidebar items strictly by path
    return allowedPaths.includes(item.path);
  });

  /* Sidebar Logic */
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const toggleSidebar = () => setSidebarOpen(!isSidebarOpen);

  return (
    <div className="dashboard-layout">
      {/* Mobile Header (Only visible < 768px via CSS) */}
      <div className="mobile-header" style={{
        padding: '1rem',
        borderBottom: '1px solid var(--bg-tertiary)',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        backgroundColor: 'var(--bg-secondary)',
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 998
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <button onClick={toggleSidebar} style={{ background: 'none', border: 'none', color: 'white', cursor: 'pointer' }}>
            <Menu size={24} />
          </button>
          <h1 style={{ fontSize: '1.2rem', fontWeight: 'bold', color: 'var(--primary)', margin: 0 }}>Chefia</h1>
        </div>
        <div style={{ width: '32px', height: '32px', borderRadius: '50%', backgroundColor: 'var(--bg-tertiary)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          {user.name?.charAt(0) || 'A'}
        </div>
      </div>

      {/* Sidebar Overlay (Mobile Only) */}
      {isSidebarOpen && (
        <div
          className="sidebar-overlay"
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div style={{ padding: '2rem', borderBottom: '1px solid var(--bg-tertiary)' }}>
          <h1 style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--primary)', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            Chefia
            {/* Close Button Mobile */}
            <button className="mobile-only-btn" onClick={() => setSidebarOpen(false)} style={{ background: 'none', border: 'none', color: 'var(--text-secondary)' }}>
              <X size={24} />
            </button>
          </h1>
          <p style={{ fontSize: '0.9rem', color: 'var(--text-secondary)' }}>
            {userRole === 'gerente' ? 'Gestão Completa' :
              userRole === 'recepcao' ? 'Recepção' :
                userRole === 'cozinha' ? 'Cozinha' : 'Bar'}
          </p>
        </div>

        <nav style={{ flex: 1, padding: '1rem' }}>
          {filteredNavItems.map(item => (
            <NavLink
              key={item.path}
              to={item.path}
              onClick={() => setSidebarOpen(false)} // Auto close on click mobile
              style={({ isActive }) => ({
                display: 'flex', alignItems: 'center', gap: '0.75rem',
                padding: '0.75rem 1rem', marginBottom: '0.5rem', borderRadius: '0.5rem',
                textDecoration: 'none',
                color: isActive ? 'white' : 'var(--text-secondary)',
                backgroundColor: isActive ? 'var(--primary)' : 'transparent',
                fontWeight: isActive ? '600' : '400',
                transition: 'all 0.2s'
              })}
            >
              <item.icon size={20} />
              {item.label}
            </NavLink>
          ))}
        </nav>

        <div style={{ padding: '1rem', borderTop: '1px solid var(--bg-tertiary)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem', padding: '0 1rem' }}>
            <div style={{ width: '32px', height: '32px', borderRadius: '50%', backgroundColor: 'var(--bg-tertiary)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              {user.name?.charAt(0) || 'A'}
            </div>
            <div>
              <p style={{ fontSize: '0.9rem', fontWeight: '500', color: 'var(--text-primary)' }}>{user.name || 'Admin'}</p>
              <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Gerente</p>
            </div>
          </div>
          <button
            onClick={handleLogout}
            style={{
              width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem',
              padding: '0.5rem', border: 'none', borderRadius: '0.5rem',
              backgroundColor: 'rgba(239, 68, 68, 0.1)', color: 'var(--danger)', cursor: 'pointer',
              transition: 'background-color 0.2s'
            }}
            onMouseOver={(e) => e.currentTarget.style.backgroundColor = 'rgba(239, 68, 68, 0.2)'}
            onMouseOut={(e) => e.currentTarget.style.backgroundColor = 'rgba(239, 68, 68, 0.1)'}
          >
            <LogOut size={18} /> Sair
          </button>
        </div>
      </aside >

      {/* Main Content */}
      < main className="main-content" >
        {children}
      </main >
    </div >
  );
};

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/login" element={<Login />} />

        <Route path="/" element={<RequireAuth><LayoutWrapper><Dashboard /></LayoutWrapper></RequireAuth>} />
        <Route path="/kitchen" element={<RequireAuth><LayoutWrapper><Kitchen /></LayoutWrapper></RequireAuth>} />
        <Route path="/table/:id" element={<RequireAuth><LayoutWrapper><TableDetail /></LayoutWrapper></RequireAuth>} />
        <Route path="/sales" element={<RequireAuth><LayoutWrapper><Sales /></LayoutWrapper></RequireAuth>} />
        <Route path="/suppliers" element={<RequireAuth><LayoutWrapper><Suppliers /></LayoutWrapper></RequireAuth>} />
        <Route path="/menu" element={<RequireAuth><LayoutWrapper><MenuManager /></LayoutWrapper></RequireAuth>} />
        <Route path="/team" element={<RequireAuth><LayoutWrapper><Team /></LayoutWrapper></RequireAuth>} />
        <Route path="/qr" element={<RequireAuth><LayoutWrapper><QRGenerator /></LayoutWrapper></RequireAuth>} />
        <Route path="/settings" element={<RequireAuth><LayoutWrapper><Settings /></LayoutWrapper></RequireAuth>} />

        {/* Catch all - Redirect to Home */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </Router>
  );
}

export default App;

import { useState, useEffect } from 'react';
import { supabase } from '../services/api';
import { Clock, ChefHat, CheckCircle } from 'lucide-react';
import dayjs from 'dayjs';
import relativeTime from 'dayjs/plugin/relativeTime';
import 'dayjs/locale/pt-br';

dayjs.extend(relativeTime);
dayjs.locale('pt-br');

const Kitchen = () => {
    const [orders, setOrders] = useState([]);

    useEffect(() => {
        const fetchOrders = async () => {
            const { data } = await supabase
                .from('orders')
                .select(`
                    *,
                    tables (number),
                    products (name, category)
                `)
                .gt('price', 0)
                .in('status', ['pending', 'preparing', 'ready'])
                .order('created_at', { ascending: true }); // Oldest first

            if (data) setOrders(data);
        };

        fetchOrders();

        const channel = supabase
            .channel('kitchen-realtime')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'orders' }, () => fetchOrders())
            .subscribe();

        return () => supabase.removeChannel(channel);
    }, []);

    const updateStatus = async (id, newStatus) => {
        await supabase
            .from('orders')
            .update({ status: newStatus })
            .eq('id', id);
    };

    const OrderCard = ({ order }) => {
        const timeElapsed = dayjs(order.created_at).fromNow(true);
        const isLate = dayjs().diff(dayjs(order.created_at), 'minute') > 20;

        return (
            <div className="card" style={{
                borderLeft: isLate ? '4px solid var(--danger)' : '4px solid var(--primary)',
                animation: 'fadeIn 0.3s ease-in'
            }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                    <span style={{ fontWeight: 'bold', fontSize: '1.1rem' }}>Mesa {order.tables?.number}</span>
                    <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', gap: '4px' }}>
                        <Clock size={14} /> {timeElapsed}
                    </span>
                </div>

                <div style={{ marginBottom: '1rem' }}>
                    <div style={{ fontSize: '1.2rem', fontWeight: '500' }}>
                        {order.quantity}x {order.name}
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '0.5rem' }}>
                    {order.status === 'pending' && (
                        <button
                            className="btn btn-primary"
                            style={{ width: '100%' }}
                            onClick={() => updateStatus(order.id, 'preparing')}
                        >
                            <ChefHat size={18} style={{ marginRight: '8px' }} /> Iniciar
                        </button>
                    )}
                    {order.status === 'preparing' && (
                        <button
                            className="btn btn-success"
                            style={{ width: '100%', backgroundColor: 'var(--success)' }}
                            onClick={() => updateStatus(order.id, 'ready')}
                        >
                            <CheckCircle size={18} style={{ marginRight: '8px' }} /> Pronto
                        </button>
                    )}
                    {order.status === 'ready' && (
                        <button
                            className="btn"
                            style={{ width: '100%', backgroundColor: 'var(--bg-tertiary)', color: 'var(--text-primary)' }}
                            onClick={() => updateStatus(order.id, 'delivered')}
                        >
                            Entregue
                        </button>
                    )}
                </div>
            </div>
        );
    };

    const Columns = ({ title, status, color, icon: Icon }) => (
        <div style={{ flex: 1, minWidth: '300px' }}>
            <div style={{
                display: 'flex', alignItems: 'center', gap: '0.5rem',
                marginBottom: '1rem', paddingBottom: '0.5rem',
                borderBottom: `2px solid ${color}`
            }}>
                <Icon size={20} color={color} />
                <h3 style={{ margin: 0 }}>{title} ({orders.filter(o => o.status === status).length})</h3>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {orders.filter(o => o.status === status).map(order => (
                    <OrderCard key={order.id} order={order} />
                ))}
            </div>
        </div>
    );

    return (
        <div style={{ height: 'calc(100vh - 4rem)', display: 'flex', flexDirection: 'column' }}>
            <h1>Cozinha (KDS) 👨‍🍳</h1>
            <div style={{ display: 'flex', gap: '2rem', overflowX: 'auto', paddingBottom: '1rem', flex: 1 }}>
                <Columns title="A Fazer" status="pending" color="var(--warning)" icon={Clock} />
                <Columns title="Preparando" status="preparing" color="var(--primary)" icon={ChefHat} />
                <Columns title="Pronto" status="ready" color="var(--success)" icon={CheckCircle} />
            </div>
        </div>
    );
};

export default Kitchen;

import React, { useState } from 'react';
import { FileSpreadsheet, Upload, Download } from 'lucide-react';

const MenuImporter = ({ onDownloadTemplate }) => {
    const [dragActive, setDragActive] = useState(false);
    const [uploadStatus, setUploadStatus] = useState('idle');

    const handleDrag = (e) => {
        e.preventDefault();
        e.stopPropagation();
        if (e.type === "dragenter" || e.type === "dragover") {
            setDragActive(true);
        } else if (e.type === "dragleave") {
            setDragActive(false);
        }
    };

    const handleDrop = (e) => {
        e.preventDefault();
        e.stopPropagation();
        setDragActive(false);
        if (e.dataTransfer.files && e.dataTransfer.files[0]) {
            handleFile(e.dataTransfer.files[0]);
        }
    };

    const handleFile = (file) => {
        setUploadStatus('uploading');
        // Mock upload simulation
        setTimeout(() => {
            setUploadStatus('success');
            // Here we would actually parse the CSV and call an onImport function
            alert('Funcionalidade de processamento de CSV simulada.');
        }, 1500);
    };

    return (
        <div className="glass-panel" style={{ padding: '3rem', borderRadius: 'var(--radius)', textAlign: 'center' }}>
            <div style={{ maxWidth: '500px', margin: '0 auto' }}>
                <div style={{ width: '60px', height: '60px', background: 'rgba(99, 102, 241, 0.1)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 1.5rem auto' }}>
                    <FileSpreadsheet size={30} className="text-primary" />
                </div>
                <h2 style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>Importação em Massa</h2>
                <p style={{ color: 'var(--text-secondary)', marginBottom: '2rem' }}>
                    Arraste seu arquivo CSV ou clique para selecionar.
                </p>

                {/* Drag and Drop Area */}
                <div
                    onDragEnter={handleDrag}
                    onDragLeave={handleDrag}
                    onDragOver={handleDrag}
                    onDrop={handleDrop}
                    style={{
                        border: '2px dashed var(--glass-border)',
                        borderRadius: '12px',
                        padding: '3rem',
                        backgroundColor: dragActive ? 'rgba(99, 102, 241, 0.05)' : 'transparent',
                        transition: 'all 0.2s',
                        marginBottom: '2rem'
                    }}
                >
                    <Upload size={40} color="var(--text-secondary)" style={{ marginBottom: '1rem' }} />
                    <p>Solte o arquivo aqui</p>
                </div>

                <button onClick={onDownloadTemplate} className="btn" style={{ color: 'var(--primary)', fontWeight: 600 }}>
                    <Download size={18} style={{ marginRight: '0.5rem', verticalAlign: 'middle' }} />
                    Baixar Modelo CSV
                </button>
            </div>
        </div>
    );
};

export default MenuImporter;

import React, { useState, useEffect } from 'react';
import { X, CheckCircle } from 'lucide-react';

const ProductFormModal = ({ isOpen, onClose, product, onSubmit }) => {
    const categories = ['Lanches', 'Bebidas', 'Porções', 'Sobremesas', 'Combos'];

    const [formData, setFormData] = useState({
        name: '',
        category: 'Lanches',
        price: '',
        description: '',
        image_url: '',
        stock_quantity: 0,
        min_stock_level: 5
    });

    useEffect(() => {
        if (isOpen) {
            if (product) {
                setFormData({
                    name: product.name,
                    category: product.category,
                    price: product.price,
                    description: product.description || '',
                    image_url: product.image_url || '',
                    stock_quantity: product.stock_quantity || 0,
                    min_stock_level: product.min_stock_level || 5
                });
            } else {
                setFormData({
                    name: '',
                    category: 'Lanches',
                    price: '',
                    description: '',
                    image_url: '',
                    stock_quantity: 0,
                    min_stock_level: 5
                });
            }
        }
    }, [isOpen, product]);

    const handleSubmit = (e) => {
        e.preventDefault();
        onSubmit(formData);
    };

    if (!isOpen) return null;

    return (
        <div className="modal-overlay">
            <div className="modal-content glass-panel" style={{ padding: '2rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                    <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold' }}>
                        {product ? 'Editar Produto' : 'Novo Produto'}
                    </h2>
                    <button onClick={onClose} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-secondary)' }}>
                        <X size={24} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} style={{ display: 'grid', gap: '1.5rem' }}>
                    {/* Image Preview / URL */}
                    <div style={{ display: 'flex', gap: '1.5rem' }}>
                        <div style={{
                            width: '100px', height: '100px',
                            borderRadius: '12px',
                            background: 'var(--bg-tertiary)',
                            backgroundImage: `url(${formData.image_url})`,
                            backgroundSize: 'cover',
                            backgroundPosition: 'center',
                            border: '1px solid var(--glass-border)',
                            flexShrink: 0
                        }} />
                        <div style={{ flex: 1 }}>
                            <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>URL da Imagem</label>
                            <input
                                type="url"
                                placeholder="https://exemplo.com/foto.jpg"
                                value={formData.image_url}
                                onChange={e => setFormData({ ...formData, image_url: e.target.value })}
                                style={{ width: '100%', padding: '0.75rem', background: 'var(--bg-primary)', border: '1px solid var(--glass-border)', borderRadius: '8px', color: 'white' }}
                            />
                            <p style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: '0.5rem' }}>Cole o link de uma imagem externa.</p>
                        </div>
                    </div>

                    <div className="input-grid">
                        <div>
                            <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Nome do Produto</label>
                            <input
                                type="text"
                                required
                                value={formData.name}
                                onChange={e => setFormData({ ...formData, name: e.target.value })}
                                style={{ width: '100%', padding: '0.75rem', background: 'var(--bg-primary)', border: '1px solid var(--glass-border)', borderRadius: '8px', color: 'white' }}
                            />
                        </div>
                        <div>
                            <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Categoria</label>
                            <select
                                value={formData.category}
                                onChange={e => setFormData({ ...formData, category: e.target.value })}
                                style={{ width: '100%', padding: '0.75rem', background: 'var(--bg-primary)', border: '1px solid var(--glass-border)', borderRadius: '8px', color: 'white' }}
                            >
                                {categories.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                        </div>
                    </div>

                    <div className="input-grid">
                        <div>
                            <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Preço (R$)</label>
                            <input
                                type="number"
                                step="0.01"
                                required
                                value={formData.price}
                                onChange={e => setFormData({ ...formData, price: e.target.value })}
                                style={{ width: '100%', padding: '0.75rem', background: 'var(--bg-primary)', border: '1px solid var(--glass-border)', borderRadius: '8px', color: 'white' }}
                            />
                        </div>
                        <div>
                            {/* Spacer/Empty */}
                        </div>
                    </div>

                    {/* Stock Control */}
                    <div style={{ padding: '1rem', background: 'rgba(99, 102, 241, 0.05)', borderRadius: '8px', border: '1px solid rgba(99, 102, 241, 0.1)' }}>
                        <h4 style={{ fontSize: '0.9rem', color: 'var(--primary)', marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <CheckCircle size={14} /> Controle de Estoque
                        </h4>
                        <div className="input-grid">
                            <div>
                                <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Qtd. Atual</label>
                                <input
                                    type="number"
                                    value={formData.stock_quantity}
                                    onChange={e => setFormData({ ...formData, stock_quantity: e.target.value })}
                                    style={{ width: '100%', padding: '0.75rem', background: 'var(--bg-primary)', border: '1px solid var(--glass-border)', borderRadius: '8px', color: 'white' }}
                                />
                            </div>
                            <div>
                                <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Mínimo (Alerta)</label>
                                <input
                                    type="number"
                                    value={formData.min_stock_level}
                                    onChange={e => setFormData({ ...formData, min_stock_level: e.target.value })}
                                    style={{ width: '100%', padding: '0.75rem', background: 'var(--bg-primary)', border: '1px solid var(--glass-border)', borderRadius: '8px', color: 'white' }}
                                />
                            </div>
                        </div>
                    </div>

                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem', marginTop: '2rem' }}>
                        <button
                            type="button"
                            onClick={onClose}
                            className="btn"
                            style={{ backgroundColor: 'var(--bg-secondary)', color: 'var(--text-secondary)' }}
                        >
                            Cancelar
                        </button>
                        <button
                            type="submit"
                            className="btn btn-primary"
                        >
                            Salvar Produto
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default ProductFormModal;

import React, { useState, useEffect } from 'react';
import { api, supabase } from '../../services/api';
import { Plus, List, FileSpreadsheet } from 'lucide-react';

import ProductList from './components/ProductList';
import ProductFormModal from './components/ProductFormModal';
import CategoryOrderManager from './components/CategoryOrderManager';
import MenuImporter from './components/MenuImporter';

const MenuManager = () => {
    // --- STATE ---
    const [products, setProducts] = useState([]);
    const [activeTab, setActiveTab] = useState('list');

    // Order State
    const [categoryOrder, setCategoryOrder] = useState([]);
    const [hiddenCategories, setHiddenCategories] = useState([]);
    const [loadingOrder, setLoadingOrder] = useState(false);
    const [savingOrder, setSavingOrder] = useState(false);

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingProduct, setEditingProduct] = useState(null);

    // --- EFFECTS ---
    useEffect(() => {
        loadProducts();
    }, []);

    useEffect(() => {
        if (activeTab === 'order') {
            loadCategoryOrder();
        }
    }, [activeTab]);

    // --- LOAD DATA ---
    const loadProducts = async () => {
        const data = await api.getProducts();
        setProducts(data);
        return data;
    };

    const loadCategoryOrder = async () => {
        setLoadingOrder(true);
        try {
            // Get current order from settings
            const { data: estab } = await supabase
                .from('establishments')
                .select('settings')
                .eq('id', 1)
                .single();

            const savedOrder = (estab?.settings && estab.settings.category_order) || [];
            const savedHidden = (estab?.settings && estab.settings.hidden_categories) || [];

            // Get all unique categories from products
            let currentProducts = products;
            if (currentProducts.length === 0) {
                currentProducts = await loadProducts();
            }

            const uniqueCats = [...new Set(currentProducts.map(p => p.category))].filter(Boolean);

            // Split into Visible and Hidden based on settings
            const visibleCatsFromSettings = uniqueCats.filter(cat => !savedHidden.includes(cat));
            const hiddenCatsFromSettings = uniqueCats.filter(cat => savedHidden.includes(cat));

            // Construct Order Logic for Visible
            const combinedOrder = [];
            // 1. Add saved order items IF they are still visible and exist
            savedOrder.forEach(cat => {
                if (visibleCatsFromSettings.includes(cat)) {
                    combinedOrder.push(cat);
                }
            });
            // 2. Append new visible categories that weren't in saved order
            visibleCatsFromSettings.forEach(cat => {
                if (!combinedOrder.includes(cat)) {
                    combinedOrder.push(cat);
                }
            });

            setCategoryOrder(combinedOrder);
            setHiddenCategories(hiddenCatsFromSettings);
        } catch (error) {
            console.error("Error loading order", error);
        } finally {
            setLoadingOrder(false);
        }
    };

    // --- AGGREGATE HANDLERS ---

    // Products CRUD
    const handleOpenModal = (product = null) => {
        setEditingProduct(product);
        setIsModalOpen(true);
    };

    const handleProductSave = async (formData) => {
        try {
            const payload = {
                ...formData,
                price: parseFloat(formData.price),
                stock_quantity: parseInt(formData.stock_quantity),
                min_stock_level: parseInt(formData.min_stock_level)
            };

            if (editingProduct) {
                await api.updateProduct(editingProduct.id, payload);
            } else {
                await api.createProduct(payload);
            }

            setIsModalOpen(false);
            loadProducts();
        } catch (error) {
            console.error('Erro ao salvar produto:', error);
            alert('Erro ao salvar produto.');
        }
    };

    const handleDeleteProduct = async (id) => {
        if (confirm('Tem certeza que deseja excluir este produto?')) {
            try {
                await api.deleteProduct(id);
                loadProducts();
            } catch (error) {
                console.error('Erro ao excluir:', error);
                alert('Erro ao excluir produto.');
            }
        }
    };

    // Category Order & Visibility
    const toggleHideCategory = (cat) => {
        if (hiddenCategories.includes(cat)) {
            // Unhide
            setHiddenCategories(hiddenCategories.filter(c => c !== cat));
            setCategoryOrder([...categoryOrder, cat]);
        } else {
            // Hide
            setCategoryOrder(categoryOrder.filter(c => c !== cat));
            setHiddenCategories([...hiddenCategories, cat]);
        }
    };

    const moveCategory = (index, direction) => {
        const newOrder = [...categoryOrder];
        if (direction === 'left' && index > 0) {
            [newOrder[index], newOrder[index - 1]] = [newOrder[index - 1], newOrder[index]];
        } else if (direction === 'right' && index < newOrder.length - 1) {
            [newOrder[index], newOrder[index + 1]] = [newOrder[index + 1], newOrder[index]];
        }
        setCategoryOrder(newOrder);
    };

    const saveCategoryOrder = async () => {
        setSavingOrder(true);
        try {
            const { data: estab } = await supabase
                .from('establishments')
                .select('settings')
                .eq('id', 1)
                .single();

            const currentSettings = estab?.settings || {};

            const { error } = await supabase
                .from('establishments')
                .update({
                    settings: {
                        ...currentSettings,
                        category_order: categoryOrder,
                        hidden_categories: hiddenCategories
                    }
                })
                .eq('id', 1);

            if (error) throw error;
            alert('Ordem salva com sucesso!');
        } catch (error) {
            console.error(error);
            alert('Erro ao salvar ordem.');
        } finally {
            setSavingOrder(false);
        }
    };

    const handleRenameCategory = async (oldName, newName) => {
        // Validation moved here or in component - component does basic check, we do deep check
        if (categoryOrder.includes(newName) || hiddenCategories.includes(newName)) {
            alert('Já existe uma categoria com este nome.');
            throw new Error('Duplicate name');
        }

        try {
            setLoadingOrder(true);

            // 1. Update DB (Products)
            const { error } = await supabase
                .from('products')
                .update({ category: newName })
                .eq('category', oldName);

            if (error) throw error;

            // 2. Update Local State (Order)
            const newOrder = categoryOrder.map(c => c === oldName ? newName : c);
            setCategoryOrder(newOrder);

            // 3. Update Local State (Products)
            setProducts(products.map(p => p.category === oldName ? { ...p, category: newName } : p));

            // 4. Update Settings
            const { data: estab } = await supabase
                .from('establishments')
                .select('settings')
                .eq('id', 1)
                .single();
            const currentSettings = estab?.settings || {};

            await supabase
                .from('establishments')
                .update({
                    settings: {
                        ...currentSettings,
                        category_order: newOrder
                    }
                })
                .eq('id', 1);

            alert('Categoria renomeada com sucesso!');

        } catch (error) {
            console.error(error);
            alert('Erro ao renomear categoria.');
            throw error;
        } finally {
            setLoadingOrder(false);
        }
    };

    return (
        <div style={{ maxWidth: '1200px', margin: '0 auto', paddingBottom: '4rem' }}>
            <div className="header" style={{ marginBottom: '2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'end' }}>
                <div>
                    <h1 style={{ fontSize: '2rem', marginBottom: '0.5rem', fontWeight: '700', background: 'linear-gradient(to right, #fff, #94a3b8)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>Cardápio Digital</h1>
                    <p style={{ color: 'var(--text-secondary)' }}>Gerencie seus produtos, imagens e estoque.</p>
                </div>
                <button
                    onClick={() => handleOpenModal()}
                    className="btn btn-primary"
                    style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}
                >
                    <Plus size={20} /> Novo Produto
                </button>
            </div>

            {/* Tabs Navigation */}
            <div style={{ display: 'flex', gap: '1rem', marginBottom: '1.5rem', borderBottom: '1px solid var(--glass-border)' }}>
                <button
                    onClick={() => setActiveTab('list')}
                    style={{
                        padding: '1rem', background: 'none', border: 'none', cursor: 'pointer',
                        borderBottom: activeTab === 'list' ? '2px solid var(--primary)' : '2px solid transparent',
                        color: activeTab === 'list' ? 'var(--primary)' : 'var(--text-secondary)',
                        fontWeight: '600', transition: 'all 0.3s'
                    }}
                >
                    Gerenciar Pratos
                </button>
                <button
                    onClick={() => setActiveTab('import')}
                    style={{
                        padding: '1rem', background: 'none', border: 'none', cursor: 'pointer',
                        borderBottom: activeTab === 'import' ? '2px solid var(--primary)' : '2px solid transparent',
                        color: activeTab === 'import' ? 'var(--primary)' : 'var(--text-secondary)',
                        fontWeight: '600',
                        display: 'flex', alignItems: 'center', gap: '6px', transition: 'all 0.3s'
                    }}
                >
                    <FileSpreadsheet size={18} /> Importar CSV
                </button>
                <button
                    onClick={() => setActiveTab('order')}
                    style={{
                        padding: '1rem', background: 'none', border: 'none', cursor: 'pointer',
                        borderBottom: activeTab === 'order' ? '2px solid var(--primary)' : '2px solid transparent',
                        color: activeTab === 'order' ? 'var(--primary)' : 'var(--text-secondary)',
                        fontWeight: '600',
                        display: 'flex', alignItems: 'center', gap: '6px', transition: 'all 0.3s'
                    }}
                >
                    <List size={18} /> Reordenar Abas
                </button>
            </div>

            {/* Tab Content */}
            <div className="animate-fade-in">
                {activeTab === 'list' && (
                    <ProductList
                        products={products}
                        onEdit={handleOpenModal}
                        onDelete={handleDeleteProduct}
                    />
                )}

                {activeTab === 'import' && (
                    <MenuImporter
                        onDownloadTemplate={() => {
                            const csvContent = "data:text/csv;charset=utf-8,Nome,Categoria,Preço,Descrição\nEx: Hamburguer,Lanches,25.00,Pão e carne";
                            const encodedUri = encodeURI(csvContent);
                            const link = document.createElement("a");
                            link.setAttribute("href", encodedUri);
                            link.setAttribute("download", "modelo_importacao_cardapio.csv");
                            document.body.appendChild(link);
                            link.click();
                        }}
                    />
                )}

                {activeTab === 'order' && (
                    <CategoryOrderManager
                        categoryOrder={categoryOrder}
                        hiddenCategories={hiddenCategories}
                        loadingOrder={loadingOrder}
                        savingOrder={savingOrder}
                        onMoveCategory={moveCategory}
                        onToggleHide={toggleHideCategory}
                        onSaveOrder={saveCategoryOrder}
                        onRenameCategory={handleRenameCategory}
                    />
                )}
            </div>

            {/* Product Modal */}
            <ProductFormModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                product={editingProduct}
                onSubmit={handleProductSave}
            />
        </div>
    );
};

