                                                    <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>{sup.email}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td style={{ padding: '1rem' }}>
                                            <span style={{
                                                padding: '4px 10px', borderRadius: '6px', fontSize: '0.75rem', fontWeight: '600',
